{
  "schema_version": "1.0",
  "document_id": "SSOT_DRIVEN_REFACTOR_EXECUTION_INSTRUCTIONS",
  "title": "AI Execution Instructions: SSOT-Driven Refactor (Registry → IDs/Modules → Planning → Templates)",
  "principles": {
    "authoritative_inputs_only": true,
    "no_implied_behavior": true,
    "deterministic_ordering": {
      "primary_sort": "file_id_ascending",
      "secondary_sort": "source_relpath_ascending"
    },
    "two_phase_apply": {
      "phase_a": "PLAN_AND_PATCH (generate SSOT + patch registry; NO moves)",
      "phase_b": "MOVE_AND_REWRITE (moves + rewrites; NO registry guessing)"
    },
    "fail_closed_and_rollback_ready": {
      "on_any_validation_failure": {
        "stop_immediately": true,
        "write_artifacts": [
          "EVIDENCE_BUNDLE/rollback_instructions.md",
          "EVIDENCE_BUNDLE/failure_fingerprint.json"
        ]
      }
    }
  },
  "authoritative_inputs": {
    "must_not_invent": true,
    "required_sources": [
      {
        "name": "final_consolidated_status_and_readiness_context",
        "lookup_rule": "Must be provided by user OR discovered by searching recent project files; do not fabricate.",
        "path_or_id": null
      },
      {
        "name": "file_classification_signals_and_decision_tree",
        "lookup_rule": "Must be provided by user OR discovered in project docs; do not fabricate.",
        "path_or_id": null
      },
      {
        "name": "unified_registry_structure_headers_file_list",
        "lookup_rule": "Read the unified registry JSON and use its current structure/columns as truth.",
        "path_or_id": "01260207201000001250_REGISTRY/01999000042260124503_governance_registry_unified.json"
      },
      {
        "name": "registry_path_update_precedent",
        "lookup_rule": "Follow the precedent for backups, updated field list, and update counts.",
        "path_or_id": "01260207201000001250_REGISTRY/01999000042260124503_REGISTRY_file.json (path update run report governs behavior)"
      },
      {
        "name": "existing_registry_sync_utility_behavior",
        "lookup_rule": "Use existing derivation patterns (layer/artifact_kind/etc.); do not create new heuristics unless explicitly authored into SSOT artifacts.",
        "path_or_id": null
      },
      {
        "name": "recursive_file_id_assignment_utility_behavior",
        "lookup_rule": "Use existing allocator + naming/exclusions; do not mutate counter store outside controlled runs.",
        "path_or_id": "P_01260207201000000109_add_file_ids.py"
      },
      {
        "name": "counter_store_format",
        "lookup_rule": "Read-only unless executing controlled allocator runs; never mutate during tests or dry runs.",
        "path_or_id": "*COUNTER_STORE.json"
      }
    ]
  },
  "objective": {
    "definition_of_done": {
      "driven_only_by_ssot_artifacts": [
        "MOVE_MAP.json",
        "REFERENCE_INDEX.json",
        "REWRITE_PATCHSET/",
        "EVIDENCE_BUNDLE/"
      ],
      "acceptance_outcome": [
        "Registry updated FIRST (module assignment points to destination dir_id).",
        "Files moved SECOND (filesystem matches MOVE_MAP; only after human approval).",
        "Imports/paths rewritten THIRD (codebase compiles/tests pass).",
        "Evidence bundle proves: before/after hashes, registry diffs, rewrite diffs, move logs, validation results."
      ]
    }
  },
  "ssot_artifacts": {
    "MOVE_MAP": {
      "path": "MOVE_MAP.json",
      "purpose": "Single source of truth for the ONLY allowed relocations.",
      "default_move_enabled": false,
      "global_fields": [
        "schema_version",
        "generated_utc",
        "repo_root",
        "dir_id_resolution",
        "counts_by_category"
      ],
      "record_fields": [
        "entity_type",
        "file_id",
        "source_relpath",
        "dest_dir_id",
        "dest_dir_relpath",
        "dest_relpath",
        "category",
        "confidence",
        "match_signals",
        "move_enabled"
      ],
      "constraints": {
        "entity_type_enum": ["file", "dir"],
        "file_id_format": "20_digits",
        "dir_id_format": "20_digits",
        "move_enabled_must_be_false_until_human_approval": true
      }
    },
    "REFERENCE_INDEX": {
      "path": "REFERENCE_INDEX.json",
      "purpose": "Single source of truth for ALL references that must be rewritten due to moves.",
      "record_fields": [
        "ref_id",
        "source_file_id",
        "source_relpath",
        "ref_type",
        "old_value",
        "new_value",
        "location",
        "rewrite_plan_id",
        "confidence",
        "evidence"
      ],
      "constraints": {
        "ref_id_stability_rule": "hash(file_id + old_value + new_value + location)",
        "evidence_rule": "snippet_hash_only_no_raw_content"
      },
      "ref_type_enum": [
        "PY_IMPORT",
        "FROM_IMPORT",
        "PATH_STRING",
        "JSON_POINTER",
        "YAML_PATH",
        "MD_LINK",
        "CLI_ARG",
        "POWERSHELL_PATH",
        "OTHER"
      ]
    },
    "REWRITE_PATCHSET": {
      "path": "REWRITE_PATCHSET/",
      "purpose": "Machine-executable rewrite plans (dry-run first, no edits until apply step).",
      "layout": {
        "manifest": "REWRITE_PATCHSET/manifest.json",
        "plans_dir": "REWRITE_PATCHSET/plans/",
        "plan_file_pattern": "REWRITE_PATCHSET/plans/<rewrite_plan_id>.json"
      },
      "plan_required_fields": [
        "rewrite_plan_id",
        "target_file_id",
        "target_relpath",
        "strategy",
        "pre_hash_sha256",
        "post_hash_sha256_expected",
        "operations",
        "dry_run_output_path"
      ],
      "strategy_enum": [
        "TEXT_REPLACE_SET",
        "PY_IMPORT_REWRITE",
        "JSON_POINTER_PATCH"
      ],
      "constraints": {
        "no_wildcards_unless_bounded_and_justified": true,
        "pre_hash_must_match_on_apply": true
      }
    },
    "EVIDENCE_BUNDLE": {
      "path": "EVIDENCE_BUNDLE/",
      "purpose": "Proof of correctness and deterministic reporting.",
      "required_outputs": {
        "run_manifest": "EVIDENCE_BUNDLE/run_manifest.json",
        "before_snapshot_dir": "EVIDENCE_BUNDLE/before_snapshot/",
        "after_snapshot_dir": "EVIDENCE_BUNDLE/after_snapshot/",
        "reports_dir": "EVIDENCE_BUNDLE/reports/",
        "diffs_dir": "EVIDENCE_BUNDLE/diffs/",
        "logs_dir": "EVIDENCE_BUNDLE/logs/"
      },
      "before_snapshot_files": [
        "EVIDENCE_BUNDLE/before_snapshot/registry_hashes.json",
        "EVIDENCE_BUNDLE/before_snapshot/file_hashes.json"
      ],
      "after_snapshot_files": [
        "EVIDENCE_BUNDLE/after_snapshot/registry_hashes.json",
        "EVIDENCE_BUNDLE/after_snapshot/file_hashes.json"
      ],
      "reports": [
        "EVIDENCE_BUNDLE/reports/inventory_consistency_report.md",
        "EVIDENCE_BUNDLE/reports/classification_report.md",
        "EVIDENCE_BUNDLE/reports/move_plan_report.md",
        "EVIDENCE_BUNDLE/reports/registry_patch_report.md",
        "EVIDENCE_BUNDLE/reports/rewrite_plan_report.md",
        "EVIDENCE_BUNDLE/reports/rewrite_apply_report.md",
        "EVIDENCE_BUNDLE/reports/validation_report.md",
        "EVIDENCE_BUNDLE/reports/HUMAN_MOVE_REVIEW.md"
      ],
      "diffs": [
        "EVIDENCE_BUNDLE/diffs/registry.patch.rfc6902.json",
        "EVIDENCE_BUNDLE/diffs/registry_paths_after_move.patch.rfc6902.json",
        "EVIDENCE_BUNDLE/diffs/rewrite_diffs/"
      ],
      "logs": [
        "EVIDENCE_BUNDLE/logs/move.log",
        "EVIDENCE_BUNDLE/logs/rewrite.log",
        "EVIDENCE_BUNDLE/logs/errors.jsonl"
      ]
    }
  },
  "classification": {
    "target_categories": [
      "REGISTRY_FILES",
      "ID_FILES",
      "MULTI_CLI_PLANNING",
      "TEMPLATE_OPERATIONS"
    ],
    "category_rules": {
      "REGISTRY_FILES": {
        "match_any": [
          "path_contains_segment('REGISTRY')",
          "filename_contains('registry') AND extension_in(['.json','.yaml','.yml'])",
          "content_contains_any(['column_headers','files','entries'])"
        ]
      },
      "ID_FILES": {
        "match_any": [
          "filename_contains_any(['ID_CANONICALITY','COUNTER_STORE','id_allocator','canonical_id_patterns','DIR_ID','FILE_ID'])",
          "is_part_of_id_allocation_or_validation_or_id_gates"
        ]
      },
      "MULTI_CLI_PLANNING": {
        "match_any": [
          "path_contains_any(['LP_LONG_PLAN','PHASE_','planning','phase_contract','execution plan'])",
          "content_contains_any(['workstreams','gates','phase_contract','envelope_contract','mutation set','plan conversion','multi-cli','orchestrator'])"
        ]
      },
      "TEMPLATE_OPERATIONS": {
        "match_any": [
          "filename_contains_any(['TEMPLATE','template','AUTONOMOUS_DELIVERY_TEMPLATE'])",
          "content_or_role_indicates_structured_patching_or_generation_over_canonical_artifacts"
        ]
      }
    },
    "ambiguity_rule": {
      "must_choose_one": true,
      "precedence_order": [
        "REGISTRY_FILES",
        "ID_FILES",
        "TEMPLATE_OPERATIONS",
        "MULTI_CLI_PLANNING"
      ],
      "record_all_matches_in_match_signals": true
    }
  },
  "destination_mapping": {
    "locked_destination_roots": [
      {
        "category": "REGISTRY_FILES",
        "destination_root_absolute_path": "C:\\Users\\richg\\Gov_Reg\\01260207201000001250_REGISTRY",
        "dest_dir_id_source": "folder_prefix",
        "dest_dir_id": "01260207201000001250"
      },
      {
        "category": "ID_FILES",
        "destination_root_absolute_path": "C:\\Users\\richg\\Gov_Reg\\01260207201000001162_GEU\\01260207201000001165_ID",
        "dest_dir_id_source": "folder_prefix",
        "dest_dir_id": "01260207201000001165"
      },
      {
        "category": "MULTI_CLI_PLANNING",
        "destination_root_absolute_path": "C:\\Users\\richg\\Gov_Reg\\01260207201000001221_Multi CLI",
        "dest_dir_id_source": "folder_prefix",
        "dest_dir_id": "01260207201000001221"
      },
      {
        "category": "TEMPLATE_OPERATIONS",
        "destination_root_absolute_path": "C:\\Users\\richg\\Gov_Reg\\newPhasePlanProcess",
        "dest_dir_id_source": "not_id_prefixed_root",
        "dest_dir_id": null,
        "special_rule": "Only move items into this root if the item itself already has a valid file_id/dir_id."
      }
    ],
    "dir_id_resolution_rules": {
      "must_not_fabricate": true,
      "allowed_sources": [
        "folder_name_prefix_20_digits",
        "directory_metadata_file_if_present"
      ]
    }
  },
  "eligibility_and_validations": {
    "id_required_for_moves": {
      "file_eligibility": {
        "eligible_if_any": [
          "file_id_exists_in_unified_registry_and_is_20_digits",
          "filename_is_id_prefixed('P_<20digits>_...')",
          "filename_is_id_prefixed('<20digits>_...')"
        ],
        "if_not_eligible": {
          "status": "SKIPPED_NO_ID"
        }
      },
      "dir_eligibility": {
        "required_fields_in_move_map": ["entity_type"],
        "eligible_if_all": [
          "entity_type == 'dir'",
          "folder_name_begins_with_20_digit_dir_id",
          "dir_id_registry_confirms_assignment_if_available"
        ],
        "if_not_eligible": {
          "status": "SKIPPED_NO_DIR_ID"
        }
      }
    },
    "pre_human_review_validations": [
      {
        "name": "existence_check",
        "rule": "current_absolute_path must exist on disk",
        "on_fail_status": "MISSING_ON_DISK"
      },
      {
        "name": "collision_check",
        "rule": "destination_absolute_path must NOT exist",
        "on_fail_status": "DEST_COLLISION"
      },
      {
        "name": "registry_alignment_check",
        "rule": "registry.relative_path for file_id must match filesystem relative path",
        "on_fail_status": "MISMATCH_REGISTRY_VS_FS",
        "blocks_move": true
      },
      {
        "name": "id_integrity_check",
        "rule": "file_id and dir_id are exactly 20 digits when present",
        "on_fail_status": "INVALID_ID_FORMAT"
      },
      {
        "name": "category_ambiguity_check",
        "rule": "if ambiguous and cannot be resolved by precedence, mark skipped",
        "on_fail_status": "SKIPPED_AMBIGUOUS_CATEGORY"
      }
    ]
  },
  "registry_update_policy": {
    "must_follow_precedent": true,
    "patch_format": "RFC-6902",
    "backup_required_before_write": true,
    "update_only_fields_declared_in_patch": true,
    "path_update_fields_when_applicable": [
      "relative_path",
      "directory_path",
      "absolute_path"
    ],
    "path_update_precedent_notes": {
      "behavior": "Update counts, zero errors expectation, backup creation, and field set mirrors prior path update run.",
      "reference": "Registry path update report indicates these three fields were updated with backups and counts."
    }
  },
  "module_assignment_policy": {
    "goal": "Registry module assignment points to destination dir_id.",
    "field_preference_order": [
      "module_id",
      "module_dir_id"
    ],
    "if_missing": {
      "add_column_header": "module_dir_id",
      "populate_for_all_moved_items": true
    }
  },
  "execution_plan": {
    "phase_a_plan_and_patch": {
      "must_not_move_any_files": true,
      "steps": [
        {
          "step_id": "A1",
          "name": "create_branch_and_run_id",
          "actions": [
            "create_new_git_branch_for_refactor",
            "generate_run_id",
            "write EVIDENCE_BUNDLE/run_manifest.json"
          ],
          "outputs": ["EVIDENCE_BUNDLE/run_manifest.json"]
        },
        {
          "step_id": "A2",
          "name": "build_candidate_inventory_no_changes",
          "actions": [
            "load unified registry",
            "build lookup file_id -> registry.relative_path",
            "scan filesystem to confirm paths exist",
            "hash candidate files (sha256)"
          ],
          "outputs": [
            "EVIDENCE_BUNDLE/reports/inventory_consistency_report.md",
            "EVIDENCE_BUNDLE/before_snapshot/file_hashes.json"
          ]
        },
        {
          "step_id": "A3",
          "name": "classify_files_into_4_categories",
          "actions": [
            "apply classification rules to each file",
            "record deterministic match_signals",
            "emit MOVE_MAP.json with move_enabled=false for all records"
          ],
          "outputs": [
            "MOVE_MAP.json",
            "EVIDENCE_BUNDLE/reports/classification_report.md"
          ]
        },
        {
          "step_id": "A4",
          "name": "resolve_destinations_and_finalize_move_map",
          "actions": [
            "map each category to its locked destination root",
            "resolve dest_dir_id from destination root folder prefix when present",
            "compute dest_relpath deterministically",
            "apply eligibility + pre-human-review validations",
            "keep move_enabled=false (human gate required before any move)"
          ],
          "outputs": [
            "MOVE_MAP.json",
            "EVIDENCE_BUNDLE/reports/move_plan_report.md"
          ]
        },
        {
          "step_id": "A5",
          "name": "generate_reference_index_dry_scan",
          "actions": [
            "scan referencing files for imports/paths/links/pointers",
            "compute new_value from MOVE_MAP",
            "emit REFERENCE_INDEX.json"
          ],
          "outputs": ["REFERENCE_INDEX.json"]
        },
        {
          "step_id": "A6",
          "name": "generate_rewrite_patchset_dry_run",
          "actions": [
            "create rewrite plans for impacted files",
            "compute pre_hash_sha256",
            "write dry-run diffs (no modifications)"
          ],
          "outputs": [
            "REWRITE_PATCHSET/manifest.json",
            "REWRITE_PATCHSET/plans/",
            "EVIDENCE_BUNDLE/reports/rewrite_plan_report.md"
          ]
        },
        {
          "step_id": "A7",
          "name": "patch_registry_first_no_moves",
          "actions": [
            "build RFC-6902 patch for module_dir_id (or module_id) updates for moved cohort",
            "apply patch with backup",
            "write update counts report"
          ],
          "outputs": [
            "EVIDENCE_BUNDLE/diffs/registry.patch.rfc6902.json",
            "EVIDENCE_BUNDLE/reports/registry_patch_report.md"
          ]
        },
        {
          "step_id": "A8",
          "name": "validate_registry_integrity_phase_a",
          "actions": [
            "schema validation",
            "uniqueness checks (file_id, relative_path)",
            "module_dir_id populated for moved cohort"
          ],
          "outputs": ["EVIDENCE_BUNDLE/reports/validation_report.md"]
        },
        {
          "step_id": "A9",
          "name": "produce_human_move_review_and_stop",
          "actions": [
            "write EVIDENCE_BUNDLE/reports/HUMAN_MOVE_REVIEW.md with required fields",
            "ensure MOVE_MAP.json move_enabled remains false for all records",
            "terminate execution (no moves performed)"
          ],
          "outputs": ["EVIDENCE_BUNDLE/reports/HUMAN_MOVE_REVIEW.md"],
          "stop_condition": true
        }
      ]
    },
    "phase_b_move_and_rewrite": {
      "requires_human_approval": true,
      "approval_input": "MOVE_MAP approval indicated by human; only then set move_enabled=true for approved records.",
      "steps": [
        {
          "step_id": "B1",
          "name": "move_files_and_dirs_from_move_map",
          "actions": [
            "execute moves strictly from MOVE_MAP where move_enabled=true",
            "log every move",
            "verify post-move sha256 equals pre-move sha256"
          ],
          "outputs": [
            "EVIDENCE_BUNDLE/logs/move.log",
            "EVIDENCE_BUNDLE/after_snapshot/file_hashes.json"
          ]
        },
        {
          "step_id": "B2",
          "name": "apply_rewrites_from_patchset",
          "actions": [
            "enforce pre_hash_sha256 match",
            "apply operations",
            "write unified diffs per file",
            "compute post-hash"
          ],
          "outputs": [
            "EVIDENCE_BUNDLE/diffs/rewrite_diffs/",
            "EVIDENCE_BUNDLE/reports/rewrite_apply_report.md",
            "EVIDENCE_BUNDLE/logs/rewrite.log"
          ]
        },
        {
          "step_id": "B3",
          "name": "patch_registry_second_final_paths",
          "actions": [
            "update registry relative_path/directory_path/absolute_path for moved files to match filesystem",
            "follow the established path update pattern with backups and counts"
          ],
          "outputs": [
            "EVIDENCE_BUNDLE/diffs/registry_paths_after_move.patch.rfc6902.json",
            "EVIDENCE_BUNDLE/reports/registry_after_move_report.md"
          ]
        },
        {
          "step_id": "B4",
          "name": "full_validation_and_tests",
          "actions": [
            "run unit/integration tests",
            "run gates enforcing import hygiene/canonicality",
            "write final registry hashes"
          ],
          "outputs": [
            "EVIDENCE_BUNDLE/reports/validation_report.md",
            "EVIDENCE_BUNDLE/after_snapshot/registry_hashes.json"
          ]
        },
        {
          "step_id": "B5",
          "name": "commit_set",
          "actions": [
            "commit SSOT artifacts (MOVE_MAP, REFERENCE_INDEX, REWRITE_PATCHSET)",
            "commit registry patches",
            "commit moves + rewrites",
            "store evidence per policy (in git or external; must be explicit)"
          ],
          "outputs": []
        }
      ]
    }
  },
  "human_move_review_document": {
    "path": "EVIDENCE_BUNDLE/reports/HUMAN_MOVE_REVIEW.md",
    "required_per_record_fields": [
      "file_id",
      "category",
      "current_absolute_path",
      "current_relative_path",
      "destination_root_absolute_path",
      "destination_absolute_path",
      "destination_relative_path",
      "source_dir_id",
      "dest_dir_id",
      "move_enabled"
    ],
    "required_summary_fields": [
      "total_candidates",
      "total_eligible",
      "skipped_no_file_id",
      "skipped_ambiguous_category",
      "skipped_destination_collision"
    ],
    "hard_stop_after_write": true
  },
  "cli_contracts": {
    "rule": "Commands must map 1:1 to steps. If missing, create minimal deterministic scripts; no ad-hoc manual logic.",
    "commands": [
      {
        "name": "cli refactor plan",
        "maps_to_steps": ["A2", "A3", "A4"],
        "inputs": ["--registry <path>", "--repo-root <path>"],
        "outputs": ["MOVE_MAP.json", "EVIDENCE_BUNDLE/reports/*"]
      },
      {
        "name": "cli refactor references",
        "maps_to_steps": ["A5"],
        "inputs": ["--move-map MOVE_MAP.json"],
        "outputs": ["REFERENCE_INDEX.json"]
      },
      {
        "name": "cli refactor rewrite-plan",
        "maps_to_steps": ["A6"],
        "inputs": ["--reference-index REFERENCE_INDEX.json"],
        "outputs": ["REWRITE_PATCHSET/"]
      },
      {
        "name": "cli registry patch",
        "maps_to_steps": ["A7", "B3"],
        "inputs": ["--registry <path>", "--patch <rfc6902.json>", "--backup"],
        "outputs": ["EVIDENCE_BUNDLE/diffs/*.rfc6902.json", "EVIDENCE_BUNDLE/reports/*"]
      },
      {
        "name": "cli validate all",
        "maps_to_steps": ["A8", "B4"],
        "inputs": ["--evidence EVIDENCE_BUNDLE/"],
        "outputs": ["EVIDENCE_BUNDLE/reports/validation_report.md"]
      },
      {
        "name": "cli refactor human-review",
        "maps_to_steps": ["A9"],
        "inputs": ["--move-map MOVE_MAP.json", "--repo-root <path>"],
        "outputs": ["EVIDENCE_BUNDLE/reports/HUMAN_MOVE_REVIEW.md"],
        "must_stop_after": true
      },
      {
        "name": "cli refactor move",
        "maps_to_steps": ["B1"],
        "inputs": ["--move-map MOVE_MAP.json"],
        "outputs": ["EVIDENCE_BUNDLE/logs/move.log", "EVIDENCE_BUNDLE/after_snapshot/file_hashes.json"],
        "requires_human_approval": true
      },
      {
        "name": "cli refactor rewrite-apply",
        "maps_to_steps": ["B2"],
        "inputs": ["--patchset REWRITE_PATCHSET/"],
        "outputs": ["EVIDENCE_BUNDLE/diffs/rewrite_diffs/", "EVIDENCE_BUNDLE/logs/rewrite.log"]
      }
    ]
  },
  "output_checklist": {
    "must_exist_end_of_phase_a": [
      "MOVE_MAP.json (move_enabled=false by default)",
      "REFERENCE_INDEX.json",
      "REWRITE_PATCHSET/manifest.json and per-file plans",
      "EVIDENCE_BUNDLE/reports/HUMAN_MOVE_REVIEW.md",
      "EVIDENCE_BUNDLE/reports/move_plan_report.md",
      "EVIDENCE_BUNDLE/reports/registry_patch_report.md",
      "EVIDENCE_BUNDLE/diffs/registry.patch.rfc6902.json"
    ],
    "must_exist_end_of_phase_b": [
